from typing import List
from collections import deque

class LinkedListNode:
  def __init__(self, val=0, next=None):
    self.val = val
    self.next = next

class Solution:
  def hasNonNilTail(self, head: LinkedListNode) -> bool:
    if head is None:
      return False
    pointer = head
    while pointer.next is not None:
      pointer = pointer.next
    return True

def read_ints():
  return list(map(int, input().split()))

def main():
  n = read_ints()[0]
  head = LinkedListNode(0)
  for x in read_ints():
    head = LinkedListNode(x, head)
  solver = Solution()
  result = solver.hasNonNilTail(head)
  print("{0}".format(result))

main()

