#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <utility>
using namespace std;

struct ListNode {
int val;
ListNode* next;

ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
bool hasNonNilTail(ListNode* head) {
  if (head == nullptr) return false;
  ListNode* pointer = head;
  while (pointer->next != nullptr) pointer = pointer->next;
  return true;
};
};

int main() {
  int n;
  cin >> n;
  ListNode head(0);
  for (int i = 0; i < n; ++i) {
    int x;
    cin >> x;
    head = ListNode(x, &head);
  }
  Solution solver;
  bool result = solver.hasNonNilTail(&head);
  cout << boolalpha << result << endl;
  return 0;
}
